{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is not a simple schema change — it redefines what a Shipment fundamentally *is*. A shipment that serves multiple recipients with different delivery preferences is closer to a Distribution or a Route than a traditional single-destination shipment. This touches the heart of the bounded context.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods in transit from an origin to one or more delivery destinations. With multi-recipient support, a Shipment becomes a container for multiple delivery obligations." },
      { "term": "Recipient", "definition": "A named party who receives a delivery, identified by name, address, phone number, and now also individual delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, signature requirements, safe-place authorization, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "AMBIGUOUS — the spec does not clarify whether one recipient is designated as primary or authoritative. This matters for billing address, notifications, and fallback routing." },
      { "term": "Shipment Status", "definition": "Previously a single state (e.g., in-transit, delivered). With multiple recipients, status becomes composite — a shipment may be partially delivered." },
      { "term": "Partial Delivery", "definition": "A new state that must exist when a multi-recipient shipment has delivered to some but not all recipients." },
      { "term": "External Partner API", "definition": "Third-party integrations that consume shipment data in the current single-recipient format and are contractually or technically coupled to that schema." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients has no delivery obligation and is logically meaningless — it would corrupt downstream routing, billing, and tracking.",
      "testable_assertion": "Any attempt to create or update a Shipment to have zero Recipients must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to physically execute a delivery. Without them, the courier cannot complete the delivery obligation.",
      "testable_assertion": "Creating a Recipient with a null or empty name, address, or phone number must fail validation."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment may have independent delivery preferences that do not affect other Recipients on the same Shipment.",
      "invariant": true,
      "invariant_justification": "Delivery preferences are per-recipient state. Mutating one recipient's preferences must never cascade to another — this is a data integrity constraint.",
      "testable_assertion": "Updating delivery preferences for Recipient A on a Shipment must not alter the preferences of Recipient B on the same Shipment."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments must remain valid and behave identically after the model change. The new model must be backward-compatible.",
      "invariant": true,
      "invariant_justification": "2 million production shipments and their associated tracking, billing, and audit records must not be corrupted. This is a data integrity constraint.",
      "testable_assertion": "After migration, every existing shipment must have exactly one Recipient with identical name, address, and phone to the original data."
    },
    {
      "id": "BR-5",
      "rule": "Shipment-level status must reflect the aggregate delivery state across all Recipients. A Shipment is 'delivered' only when ALL Recipients have received their delivery.",
      "invariant": false,
      "invariant_justification": "This is a business policy — some businesses may define 'delivered' differently (e.g., when the last recipient receives, or when a threshold is met). A VP could change this.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must NOT have status 'delivered'."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until partners have migrated to a new contract.",
      "invariant": false,
      "invariant_justification": "This is a compatibility policy driven by partner contracts, not a physical or data integrity constraint. It can be relaxed once partners upgrade.",
      "testable_assertion": "For multi-recipient shipments sent to legacy partner APIs, the system must either send one message per recipient or designate a primary recipient for the payload."
    },
    {
      "id": "BR-7",
      "rule": "Delivery preferences must have sensible defaults. A Recipient without explicit preferences must receive the shipment-level or system-level default preferences.",
      "invariant": false,
      "invariant_justification": "Default preference strategy is a business policy that can change over time.",
      "testable_assertion": "A Recipient added without delivery preferences must have a non-null preferences object populated with defaults."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies two or more Recipients with distinct addresses and delivery preferences",
      "then": "The Shipment is created successfully with all Recipients persisted and independently queryable"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The creator specifies zero Recipients",
      "then": "The system rejects the creation with a validation error"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried after the migration",
      "then": "It returns exactly one Recipient with all original data intact (name, address, phone) and the system treats it identically to pre-migration behavior"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where deliveries to Recipients A and B have succeeded but delivery to Recipient C is pending",
      "when": "The Shipment status is queried",
      "then": "The Shipment-level status reflects 'partially delivered' and each Recipient has an individual delivery status"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment is created",
      "when": "An external partner API requests this Shipment's data via the current (legacy) API contract",
      "then": "The response conforms to the single-recipient schema without errors, using a defined strategy (e.g., one call per recipient, or primary recipient only)"
    },
    {
      "id": "AC-6",
      "given": "A Shipment has multiple Recipients",
      "when": "One Recipient's delivery preferences are updated",
      "then": "No other Recipient's preferences are affected and the change is auditable"
    },
    {
      "id": "AC-7",
      "given": "A Shipment has multiple Recipients",
      "when": "The last Recipient is removed",
      "then": "The system rejects the removal to enforce the minimum-one-recipient invariant"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where two Recipients share the same address but have different delivery preferences",
      "expected_behavior": "Both Recipients are treated as distinct delivery obligations. The courier must honor each Recipient's individual preferences even though the physical destination is identical."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "The spec does not address this. Business must decide whether Recipients can be added/removed after a Shipment enters transit. This likely requires a state-machine gate."
    },
    {
      "scenario": "External partner receives a webhook for a multi-recipient Shipment but only supports single-recipient payloads",
      "expected_behavior": "The integration layer must fan-out one event per recipient or choose a designated primary recipient. The partner must never receive malformed data."
    },
    {
      "scenario": "Billing and pricing: is a multi-recipient Shipment priced as one shipment or N shipments?",
      "expected_behavior": "Undefined in spec. This has direct revenue impact and must be resolved before implementation. Pricing model must be explicit."
    },
    {
      "scenario": "Proof of delivery (POD) for multi-recipient Shipments",
      "expected_behavior": "Each Recipient must have an independent proof-of-delivery record. A single POD for the Shipment is insufficient — it would be legally and operationally ambiguous."
    },
    {
      "scenario": "Rollback scenario: a multi-recipient Shipment needs to revert to single-recipient mid-delivery",
      "expected_behavior": "Removing recipients mid-delivery has cascading effects on routing, billing, and notifications. Must be governed by explicit cancellation rules per recipient."
    },
    {
      "scenario": "Notification routing: who gets notified of Shipment-level events (e.g., pickup)?",
      "expected_behavior": "All Recipients should receive notifications relevant to them. Shipment-level events (pickup, departure) may go to all; delivery-specific events go only to the relevant Recipient."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments fundamentally change the pricing model. If a single shipment can now serve N recipients, revenue per shipment may increase (bundled pricing) or decrease (consolidation discount). The pricing/billing bounded context MUST be updated in lockstep. Additionally, partner API changes may require renegotiation of integration contracts. Migration of 2M records has direct infrastructure cost.",
    "operational": "HIGH. Courier workflows change significantly. Route optimization must now account for multiple stops per shipment. Dispatch logic, driver apps, warehouse pick/pack processes, and proof-of-delivery flows all require updates. The 'partially delivered' state introduces new exception-handling workflows that operations teams must be trained on.",
    "user": "MEDIUM-HIGH. Senders gain flexibility to ship to multiple recipients in one operation. Recipients now have personalized delivery preferences. However, tracking UX becomes more complex — a recipient should see only their delivery status, not all recipients on a shipment. Privacy implications exist: Recipient A should not see Recipient B's name or address.",
    "risk": "HIGH. This is a foundational model change affecting the core aggregate. Risks include: (1) Data migration failure corrupting 2M shipments, (2) Partner API breakage causing integration outages, (3) Inconsistent status rollups causing incorrect tracking, (4) Privacy leakage between recipients, (5) Billing discrepancies during transition period. This should be rolled out incrementally with feature flags.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain ability to create multi-recipient shipments, reducing overhead for batch deliveries. Must learn new creation flow." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. Risk of privacy exposure if isolation between co-recipients is not enforced." },
      { "group": "Couriers/Drivers", "impact": "Route and workflow changes. Must handle partial delivery states and per-recipient proof-of-delivery. Driver app UI must evolve." },
      { "group": "Operations/Dispatch", "impact": "New exception flows for partial deliveries, recipient-level failures, and split routing. Training required." },
      { "group": "External Partners", "impact": "API contract breakage risk. Must maintain backward-compatible API or provide migration path with adequate notice." },
      { "group": "Finance/Billing", "impact": "Pricing model must be redefined. Revenue recognition per shipment vs per recipient must be clarified." },
      { "group": "Customer Support", "impact": "More complex inquiry resolution. Must be able to query and act on individual recipient status within a shipment." },
      { "group": "Legal/Compliance", "impact": "Privacy obligations — recipient data isolation. Proof-of-delivery per recipient for liability. Data retention policies may need updates." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec change is stated at a very high level — 'one or more Recipients with different delivery preferences' — without defining critical business rules around pricing, status aggregation, recipient mutability during transit, partner API migration strategy, or privacy isolation. Multiple unresolved ambiguities exist that affect the core domain model. Until these are resolved, any implementation risks encoding incorrect business assumptions.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant is clear and non-negotiable",
      "Backward compatibility for 2M existing shipments is required",
      "External partner APIs need a compatibility strategy",
      "Per-recipient delivery preferences must be independent"
    ],
    "low_confidence_areas": [
      "Pricing model for multi-recipient shipments is undefined",
      "Shipment status aggregation strategy is unspecified",
      "Whether recipients can be added/removed after transit begins",
      "Privacy isolation requirements between co-recipients",
      "Partner API migration strategy (fan-out vs primary recipient)",
      "What 'delivery preferences' specifically includes"
    ],
    "assumptions": [
      "The change applies to new shipments going forward; existing shipments are migrated to the new schema but retain single-recipient semantics",
      "Each recipient represents a distinct physical delivery stop",
      "The Shipment aggregate root remains the Shipment, not the Recipient",
      "Delivery preferences are optional per recipient with system defaults"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define a pricing model for multi-recipient shipments. Is a 3-recipient shipment priced as 1 shipment, 3 shipments, or a new bundled rate? This directly affects revenue and billing system design.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Shippers", "Product"],
      "options": ["Price per shipment regardless of recipients", "Price per recipient within a shipment", "Tiered/bundled pricing model"],
      "recommendation": "Resolve with Finance and Product before implementation. This cannot be deferred — it affects the aggregate's identity and the billing bounded context integration."
    },
    {
      "type": "ambiguity",
      "description": "Shipment status aggregation is undefined. When 2 of 3 recipients are delivered, what is the shipment status? 'Partially delivered' is a new state that does not exist in the current model and has downstream effects on SLAs, reporting, and partner notifications.",
      "affected_stakeholders": ["Operations/Dispatch", "Customer Support", "External Partners"],
      "options": ["Introduce 'partially_delivered' as a new shipment-level status", "Track status only at recipient level and derive shipment status", "Keep shipment status as the worst-case across all recipients"],
      "recommendation": "Introduce explicit per-recipient delivery status and a derived shipment-level status. The derivation rule must be a documented business policy."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'different delivery preferences' but does not enumerate what delivery preferences are. Without a bounded definition, implementation will guess and likely get it wrong.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Product"],
      "options": ["Define a fixed set of preference fields now", "Create an extensible preferences model", "Start with time-window and signature-required only"],
      "recommendation": "Product must define the initial set of delivery preferences explicitly. Start minimal (time window, signature required, safe place, contactless) and extend."
    },
    {
      "type": "ambiguity",
      "description": "Partner API backward compatibility strategy is unspecified. With 2M+ shipments flowing through partner integrations, the migration path must be explicit to avoid outages.",
      "affected_stakeholders": ["External Partners", "Engineering", "Operations/Dispatch"],
      "options": ["Maintain v1 API indefinitely alongside v2", "Fan-out: send one webhook per recipient using v1 schema", "Negotiate migration timeline with each partner"],
      "recommendation": "Maintain v1 API with fan-out strategy (one event per recipient in legacy format) while building v2. Set deprecation timeline with partners."
    },
    {
      "type": "missing_context",
      "description": "Privacy and data isolation requirements between co-recipients on the same shipment are not addressed. Can Recipient A see that Recipient B exists on the same shipment? Can they see each other's addresses? This has legal and compliance implications.",
      "affected_stakeholders": ["Recipients", "Legal/Compliance", "Product"],
      "options": ["Full isolation — recipients are unaware of each other", "Visible co-recipients with masked details", "Full transparency"],
      "recommendation": "Default to full isolation. Recipients should not know about or see other recipients on the same shipment. This is the safest default from a privacy standpoint."
    },
    {
      "type": "missing_context",
      "description": "Recipient mutability after shipment enters transit is undefined. Can recipients be added or removed from an in-transit shipment? This affects routing, billing, and operational workflows significantly.",
      "affected_stakeholders": ["Senders/Shippers", "Operations/Dispatch", "Couriers/Drivers"],
      "options": ["Recipients are immutable once shipment is in transit", "Recipients can be added but not removed during transit", "Full mutability with operational constraints"],
      "recommendation": "Recipients should be immutable once a shipment enters transit, at least for v1. Allowing mid-transit changes introduces enormous routing and billing complexity."
    }
  ],

  "rejection_reasons": []
}

